public static boolean search(int[] mylist, int k) {
for (int i = 0; i < mylist.length; i++)
if (mylist[i] == k)
return true;
return false;
}
bool search(int mylist[], int k, int n) {
for (int i = 0; i < n; i++)
if (mylist[i] == k)
return true;
return false;
}
