Recursive Insert
template <class T> 
void BST<T>::insert(T& val) { 
     root = insert(val, root); 
} 
template <class T> 
Node<T>* BST<T>::insert(T& val, Node<T>* node) { 
    if (node == nullptr)  
        return new Node<T>(val, nullptr, nullptr); 
    if (val > node->val)  
        node->right = insert(val, node->right); 
    else if (val < node->val)  
        node->left  = insert(val, node->left); 
    return node; 
}
