template <class T> 
T BST<T>::get_max() const { 
    if (is_empty()) 
        throw string("No max in an empty tree"); 

    Node<T>* curr = root; 
    while (curr->right != nullptr) 
        curr = curr->right; 
    return curr->val; 
} 
template <class T> 
T BST<T>::get_min() const { 
    if (is_empty()) 
        throw string("No min in an empty tree"); 

    Node<T>* curr = root; 
    while (curr->left != nullptr) 
        curr = curr->left; 
    return curr->val; 
}
