template<class T> 
void BST<T>::remove_1(Node<T>* node, Node<T>* parent) { 
    if (node == root) { 
        if (node->left == nullptr) 
            root = root->right; 
        else  
            root = root->left; 
    } 
    else if (node == parent->right) {  
        if (node->right != nullptr) 
            parent->right = node->right; 
        else  
            parent->right = node->left; 
    }  
    else {  
        if (node->right != nullptr) 
            parent->left = node->right; 
        else 
            parent->left = node->left; 
    } 
    delete node; 
}

