Deleting a Node
finds the node with 
the given val and 
deletes it.
template<class T> 
bool BST<T>::remove(const T& val) { 
    Node<T>* prev = nullptr; 
    Node<T>* curr = root; 
    while (curr != nullptr && curr->val != val) { 
        prev = curr; 
        if (val > curr->val)  
            curr = curr->right; 
        else 
            curr = curr->left; 
    } 
    if (curr == nullptr) 
        return false; 
    if (curr->left != nullptr && curr->right != nullptr) 
        remove_2(curr); 
    else 
        remove_1(curr, prev); 
    return true; 
}

