(((5 % 10) + 6) % 10) + 23) % 10 =  
(((5     ) + 6) % 10) + 23) % 10 = 
((11          ) % 10) + 23) % 10 = 
((1                 ) + 23) % 10 = 
(24                       ) % 10 = 4 
