void sink(int a[], int i, int size) { 
    while (LEFT(i) < size) { 
        int k = LEFT(i); 
        if (RIGHT(i) < size)  
            if (a[k] < a[RIGHT(i)])  
                k = RIGHT(i); 
        if (a[i] < a[k]) 
            swap(a[i], a[k]); 
            i = k; 
        else break; 
    } 
}
int remove_max(int a[],  
            int& size) { 
  swap(a[size-1], a[0]); 
  size = size--;  
  sink(a, 0, size); 
  return a[size]; 
}
